$fn = 20;

// --- Pot / rim / soil ---
label("pot") cylinder(h = 14, r1 = 9, r2 = 11, $fn = 32);
label("rim") translate([0, 0, 13]) cylinder(h = 2.6, r = 11.8, $fn = 32);
label("soil") translate([0, 0, 14.2]) cylinder(h = 0.4, r = 10.5, $fn = 32);

// --- Cactus: body + both arms, ALL share ONE "cactus" label so green covers
//     everything. Separate top-level statements union implicitly in Manifold
//     (not CGAL), so each keeps its label. ---
label("cactus") translate([0, 0, 12.6]) union() { // body
  cylinder(h = 24, r = 5, $fn = 24);
  translate([0, 0, 24]) sphere(r = 5, $fn = 20);
}
label("cactus") translate([3, 0, 24]) rotate([0, 50, 0]) union() { // right arm
  cylinder(h = 8, r = 2.2, $fn = 18);
  translate([0, 0, 8]) sphere(r = 2.2, $fn = 16);
}
label("cactus") translate([-3, 0, 28]) rotate([0, -45, 0]) union() { // left arm
  cylinder(h = 6.5, r = 2.0, $fn = 18);
  translate([0, 0, 6.5]) sphere(r = 2.0, $fn = 16);
}

// --- Crown flower (pink) ---
label("flower") translate([0, 0, 41]) sphere(r = 2.2, $fn = 20);

// --- Face ---
// The catalog thumbnail uses the iso view (azimuth 135): camera at +X,-Y,+Z.
// rotate([0,0,45]) turns the local -Y "front" toward that +X/-Y corner so the
// face stares straight at the camera (eyes symmetric, smile un-foreshortened).
// Body cylinder spans z=12.6..36.6, radius 5; local front surface at y ~ -5.
// Eyes: two bigger round spheres sitting proud of the surface.
rotate([0, 0, 45]) label("eyeL") translate([-1.9, -4.6, 31]) sphere(r = 1.45, $fn = 22);
rotate([0, 0, 45]) label("eyeR") translate([ 1.9, -4.6, 31]) sphere(r = 1.45, $fn = 22);

// Smile: a strong upward U-arc (corners well above the dip) below the eyes —
// corners pushed forward (more -y) so they stay prominent at the iso angle.
rotate([0, 0, 45]) label("mouth") translate([-2.7, -4.55, 28.0]) sphere(r = 0.8, $fn = 16);
rotate([0, 0, 45]) label("mouth") translate([-1.9, -4.80, 27.0]) sphere(r = 0.8, $fn = 16);
rotate([0, 0, 45]) label("mouth") translate([-0.9, -4.95, 26.3]) sphere(r = 0.8, $fn = 16);
rotate([0, 0, 45]) label("mouth") translate([ 0.0, -5.00, 26.1]) sphere(r = 0.8, $fn = 16);
rotate([0, 0, 45]) label("mouth") translate([ 0.9, -4.95, 26.3]) sphere(r = 0.8, $fn = 16);
rotate([0, 0, 45]) label("mouth") translate([ 1.9, -4.80, 27.0]) sphere(r = 0.8, $fn = 16);
rotate([0, 0, 45]) label("mouth") translate([ 2.7, -4.55, 28.0]) sphere(r = 0.8, $fn = 16);

